resource.manifest:
apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{=toJSON(inputs.parameters.name)}}
  ownerReferences:
    - apiVersion: migrations.opensearch.org/v1alpha1
      kind: TrafficReplay
      name: {{=toJSON(inputs.parameters.name)}}
      uid: {{=toJSON(inputs.parameters.ownerUid)}}
      controller: true
      blockOwnerDeletion: true
  labels:
    app: replayer
    workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
    migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
    migrations.opensearch.org/target: {{=toJSON(inputs.parameters.targetK8sLabel)}}
    migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
spec:
  replicas: {{=fromJSON(inputs.parameters.podReplicas)}}
  strategy:
    type: Recreate
  selector:
    matchLabels:
      app: replayer
  template:
    metadata:
      labels:
        app: replayer
        migrations/replayer: {{=toJSON(inputs.parameters.name)}}
        workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
        migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
        migrations.opensearch.org/target: {{=toJSON(inputs.parameters.targetK8sLabel)}}
        migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
    spec:
      serviceAccountName: argo-workflow-executor
      containers:
        - name: replayer
          image: {{=toJSON(inputs.parameters.imageTrafficReplayerLocation)}}
          imagePullPolicy: {{=toJSON(inputs.parameters.imageTrafficReplayerPullPolicy)}}
          args:
            - ---INLINE-JSON
            - "{{=toBase64(inputs.parameters.jsonConfig)}}"
          resources: {{=fromJSON(inputs.parameters.resources)}}
          env:
            - name: TRAFFIC_REPLAYER_KAFKA_TRAFFIC_PASSWORD
              valueFrom:
                secretKeyRef:
                  name: {{=toJSON(inputs.parameters.kafkaSecretName)}}
                  key: password
                  optional: {{=!(inputs.parameters.kafkaAuthType == 'scram-sha-512')}}
            - name: TARGET_USERNAME
              valueFrom:
                secretKeyRef:
                  name: {{=toJSON(((0 == len(inputs.parameters.basicAuthSecretName)) ? ('empty') : (inputs.parameters.basicAuthSecretName)))}}
                  key: username
                  optional: true
            - name: TARGET_PASSWORD
              valueFrom:
                secretKeyRef:
                  name: {{=toJSON(((0 == len(inputs.parameters.basicAuthSecretName)) ? ('empty') : (inputs.parameters.basicAuthSecretName)))}}
                  key: password
                  optional: true
            - name: JDK_JAVA_OPTIONS
              value: {{=toJSON(inputs.parameters.jvmArgs + ' ' + ((!(0 == len(inputs.parameters.loggingConfigurationOverrideConfigMap))) ? ('-Dlog4j2.configurationFile=/config/logConfiguration/configuration') : ('')))}}
            - name: AWS_SHARED_CREDENTIALS_FILE
              value: {{=toJSON(((fromJSON(inputs.parameters.useLocalStack)) ? ('/config/credentials/configuration') : ('')))}}
          volumeMounts: {{=sprig.concat([sprig.dict("name", 'kafka-auth-config', "mountPath", '/config/kafka-auth', "readOnly", true), sprig.dict("name", 'kafka-ca', "mountPath", '/config/kafka-ca', "readOnly", true), sprig.dict("name", 'log4j-configuration', "mountPath", '/config/logConfiguration', "readOnly", true), sprig.dict("name", 'localstack-test-creds', "mountPath", '/config/credentials', "readOnly", true)], fromJSON(inputs.parameters.fileSourceVolumeMounts))}}
      volumes: {{=sprig.concat([sprig.dict("name", 'kafka-auth-config', "configMap", sprig.dict("name", inputs.parameters.kafkaAuthConfigMapName)), sprig.dict("name", 'kafka-ca', "secret", sprig.dict("secretName", inputs.parameters.kafkaCaSecretName, "optional", !(inputs.parameters.kafkaAuthType == 'scram-sha-512'))), sprig.dict("name", 'log4j-configuration', "configMap", sprig.dict("name", sprig.default('default-log4j-config', inputs.parameters.loggingConfigurationOverrideConfigMap), "optional", !(!(0 == len(inputs.parameters.loggingConfigurationOverrideConfigMap))))), sprig.dict("name", 'localstack-test-creds', "configMap", sprig.dict("name", 'localstack-test-creds', "optional", !(fromJSON(inputs.parameters.useLocalStack))))], fromJSON(inputs.parameters.fileSourceVolumes))}}

apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: {{=toJSON(inputs.parameters.name)}}
  ownerReferences:
    - apiVersion: migrations.opensearch.org/v1alpha1
      kind: TrafficReplay
      name: {{=toJSON(inputs.parameters.name)}}
      uid: {{=toJSON(inputs.parameters.ownerUid)}}
      controller: true
      blockOwnerDeletion: true
  labels:
    app: replayer
    workflows.argoproj.io/workflow: {{=toJSON(workflow.name)}}
    migrations.opensearch.org/source: {{=toJSON(inputs.parameters.sourceK8sLabel)}}
    migrations.opensearch.org/target: {{=toJSON(inputs.parameters.targetK8sLabel)}}
    migrations.opensearch.org/task: {{=toJSON(inputs.parameters.taskK8sLabel)}}
spec:
  minAvailable: {{=fromJSON(inputs.parameters.minPodReplicas)}}
  selector:
    matchLabels:
      migrations/replayer: {{=toJSON(inputs.parameters.name)}}
